function handleTouchAndMouse() {
  let isTouch = false;
  let lastTouchTime = 0;
  let mouseMoveListenerAdded = false;

  function onFirstTouch() {
    isTouch = true;
    lastTouchTime = Date.now();
    document.body.classList.add('touch-device');

    if (!mouseMoveListenerAdded) {
      window.addEventListener('mousemove', onMouseMove);
      mouseMoveListenerAdded = true;
    }
  }

  function onMouseMove() {
    if (Date.now() - lastTouchTime < 1000) {
      return;
    }

    if (isTouch) {
      isTouch = false;
      document.body.classList.remove('touch-device');
    }
  }

  window.addEventListener('touchstart', onFirstTouch, { passive: true });
  window.addEventListener('touchmove', () => {
    lastTouchTime = Date.now();
  }, { passive: true });

  window.addEventListener('mousemove', onMouseMove);
}

function dataTrim() {
  var ellipsis = "...";
  $("[data-trim]").each(function () {
    var text = $(this).html();
    var charLimit = parseInt($(this).attr("data-trim"));
    $(this).html(TrimLength(text, charLimit));
    $(this).addClass("is--trimmed");
  });

  function TrimLength(text, maxLength) {
    text = $.trim(text);
    if (text.length > maxLength) {
      text = text.substring(0, maxLength - ellipsis.length);
      return text.substring(0, text.lastIndexOf(" ")) + ellipsis;
    } else return text;
  }
}

function ChangeToSvg() {
  $("img.js-tosvg").each(function () {
    var $img = $(this);
    var imgID = $img.attr("id");
    var imgClass = $img.attr("class");
    var imgURL = $img.attr("src");
    $.get(
      imgURL,
      function (data) {
        var $svg = $(data).find("svg");
        if (typeof imgID !== "undefined") {
          $svg = $svg.attr("id", imgID);
        }
        if (typeof imgClass !== "undefined") {
          $svg = $svg.attr("class", imgClass + " insvg");
        }
        $svg = $svg.removeAttr("xmlns:a");
        if (
          !$svg.attr("viewBox") &&
          $svg.attr("height") &&
          $svg.attr("width")
        ) {
          $svg.attr(
            "viewBox",
            "0 0 " + $svg.attr("height") + " " + $svg.attr("width")
          );
        }
        $img.replaceWith($svg);
      },
      "xml"
    );
  });
}

