function tabsSlider() {
  document.querySelectorAll(".tabs-wrapper").forEach((wrapper) => {
    const parent = wrapper.querySelector(".nav-tabs");

    if (!parent || parent.classList.contains("vertical-slider")) return;

    wrapper.querySelectorAll(".nav-tabs .nav-link").forEach((button) => {
      button.addEventListener("click", function () {
        const btnOffset = this.offsetLeft;
        const btnWidth = this.offsetWidth;
        const parentWidth = parent.offsetWidth;

        parent.scrollTo({
          left: btnOffset - parentWidth / 2 + btnWidth / 2,
          behavior: "smooth",
        });
      });
    });
  });
}

