function tabsSliderArrow() {
  document.querySelectorAll(".tabs-wrapper-arrow").forEach((wrapper) => {
    const parent = wrapper.querySelector(".nav-tabs");
    const prevBtn = wrapper.querySelector(".previous-btn");
    const nextBtn = wrapper.querySelector(".next-btn");

    if (!parent || !prevBtn || !nextBtn) return;

    const updateButtonState = () => {
      const scrollLeft = Math.round(parent.scrollLeft);
      const scrollWidth = Math.round(parent.scrollWidth);
      const parentWidth = Math.round(parent.clientWidth);

      prevBtn.classList.toggle("disabled", scrollLeft <= 1);
      nextBtn.classList.toggle("disabled", scrollLeft + parentWidth >= scrollWidth - 4);
    };

    const scrollToNext = () => {
      const parentWidth = parent.clientWidth;
      const maxScrollLeft = parent.scrollWidth - parentWidth;
      const scrollLeft = parent.scrollLeft;
      const remainingScroll = maxScrollLeft - scrollLeft;
      const scrollAmount = Math.min(parentWidth * 0.5, remainingScroll);
      parent.scrollBy({
        left: scrollAmount,
        behavior: "smooth",
      });
    };

    const scrollToPrev = () => {
      const scrollLeft = parent.scrollLeft;
      const scrollAmount = Math.min(parent.clientWidth * 0.5, scrollLeft);

      parent.scrollBy({
        left: -scrollAmount,
        behavior: "smooth",
      });
    };

    nextBtn.addEventListener("click", scrollToNext);
    prevBtn.addEventListener("click", scrollToPrev);
    parent.addEventListener("scroll", updateButtonState);

    wrapper.querySelectorAll(".nav-tabs .nav-link").forEach((button) => {
      button.addEventListener("click", function () {
        const btnOffset = this.offsetLeft;
        const btnWidth = this.offsetWidth;
        const parentWidth = parent.offsetWidth;

        parent.scrollTo({
          left: btnOffset - parentWidth / 2 + btnWidth / 2,
          behavior: "smooth",
        });
      });
    });

    updateButtonState();
  });
}



function updateArrowVisibility() {
  const wrapper = document.querySelector('.tabs-wrapper-arrow');
  if (!wrapper) {

    return;
  }

  const navTabs = wrapper.querySelector('.nav-tabs');
  const prevBtn = wrapper.querySelector('.previous-btn');
  const nextBtn = wrapper.querySelector('.next-btn');

  // Ensure all elements exist before manipulating
  if (!navTabs || !prevBtn || !nextBtn) {

    return;
  }

  // Check if navTabs overflows its parent
  const isOverflowing = navTabs.scrollWidth > navTabs.clientWidth;

  prevBtn.style.display = isOverflowing ? 'flex' : 'none';
  nextBtn.style.display = isOverflowing ? 'flex' : 'none';
}

