function initializeFilterSystem({
  mainContainerClass,
  selectClass,
  selectedFiltersContainer,
  removeFilterClass,
  clearFilterClass,
  accordionHeaderClass,
  accordionContentClass,
  accordionFiltersClass,
  applyBtnClass,
  clearBtnClass,
  selectedOptionsClass,
}) {
  let SelectedFilters = [];
  const $container = $("." + mainContainerClass);

  $container.find("." + selectClass).each(function () {
    const $select = $(this);
    // let allowOpen = true;

    $select.select2({
      width: "100%",
      minimumResultsForSearch: Infinity,
      closeOnSelect: false,
    });
  });

  $container.on("change", "." + selectClass, function () {
    let selectId = $(this).data("id");
    let selectedValues = $(this).val() || [];
    let selectedTextArray = $(this)
      .find(":selected")
      .map(function () {
        return $(this).text();
      })
      .get();

    SelectedFilters = SelectedFilters.filter(
      (filter) =>
        !(filter.id === selectId && !selectedValues.includes(filter.value))
    );

    selectedValues.forEach((value, index) => {
      if (
        !SelectedFilters.some(
          (filter) => filter.value === value && filter.id === selectId
        )
      ) {
        SelectedFilters.push({
          id: selectId,
          text: selectedTextArray[index],
          value: value,
        });
      }
    });
    if (
      !lastClickedElement ||
      !lastClickedElement.closest("." + applyBtnClass).length
    ) {
      setSelectedOptions(selectId, selectedValues);
    }
    refreshFilterTags();

    if (SelectedFilters.length != 0) {
      $("#filter-count").text(`(${SelectedFilters.length})`);
    } else {
      $("#filter-count").text(``);
    }
  });

  function refreshFilterTags() {
    let closeBtn = `<div class="${clearFilterClass}"><p>Clear</p><div class="dash"></div></div>`;
    $container.find("." + selectedFiltersContainer).empty();
    SelectedFilters.forEach((filterObj) => {
      let filterTag = $(`
                <div class="filter-tag ${removeFilterClass}" data-id="${filterObj.id}" data-value="${filterObj.value}">
                    <div><p>${filterObj.text}</p></div>
                    <div data-id="${filterObj.id}" data-value="${filterObj.value}">
                        <img src="/assets/img/icons/filter-tag-close.svg" class="js-tosvg" alt="close">
                    </div>
                </div>
            `);
      $container.find("." + selectedFiltersContainer).append(filterTag);
    });
    if (SelectedFilters.length > 0) {
      $container.find("." + selectedFiltersContainer).append(closeBtn);
    }
  }

  $container.on("click", "." + removeFilterClass, function () {
    let idToRemove = $(this).data("id");
    let valueToRemove = $(this).data("value");
    SelectedFilters = SelectedFilters.filter(
      (filter) => !(filter.value === valueToRemove && filter.id === idToRemove)
    );
    $container
      .find(`.${selectClass}[data-id="${idToRemove}"]`)
      .val(function (index, currentValues) {
        return (currentValues || []).filter(
          (val) => val !== valueToRemove.toString()
        );
      })
      .trigger("change");
    refreshFilterTags();
  });

  $container.on("click", "." + clearFilterClass, function () {
    SelectedFilters = [];
    $container
      .find("." + selectClass)
      .val(null)
      .trigger("change");
    refreshFilterTags();
    setTimeout(() => {
      if (
        !lastClickedElement ||
        !lastClickedElement.closest("." + applyBtnClass).length
      ) {
        setSelectedOptions("", []);
      }
    }, 500);
  });

  $("." + accordionHeaderClass).on("click", function () {
    $(this)
      .toggleClass("active")
      .next("." + accordionContentClass)
      .slideToggle();
  });

  function toggleFilter(action) {

    setTimeout(function () {
      action === "open" ? $("body, html").addClass('overflowHide') : $("body, html").removeClass('overflowHide');
    }, 0);
    $(".sm-filters .filter-body").css(
      "bottom",
      action === "open" ? "0" : "-100%"
    );
  }

  $("#filter-btn, #filter-btn_open").click(function () {
    const anyCureentChecked = SelectedFilters.length > 0;
    $("." + clearBtnClass).toggleClass("disabled", !anyCureentChecked);
    $("." + applyBtnClass).toggleClass("disabled", !anyCureentChecked);
    toggleFilter("open");
  });

  $("#filter-btn_close").click(function () {
    toggleFilter("close");
    const count = SelectedFilters.length;
    $("#filter-count").text(count > 0 ? `(${count})` : "");
    $(`.${mainContainerClass} .filters input[type='checkbox']`).each(
      function () {
        let checkbox = $(this);
        let isChecked = SelectedFilters.some(
          (filter) => filter.value === checkbox.val()
        );

        checkbox.prop("checked", isChecked);
      }
    );
  });

  function getSelectedOptions(dataId) {
    let selectedOptions = [];
    $(`.${accordionFiltersClass}[data-id="${dataId}"]`)
      .find("input:checked")
      .each(function () {
        selectedOptions.push($(this).val());
      });
    return selectedOptions;
  }

  function updateSelectedOptions() {
    let selectedData = {};
    $(`.${accordionFiltersClass}`).each(function () {


      let section = $(this).data("id");
      let selectedOptions = getSelectedOptions(section);
      if (selectedOptions.length > 0) {
        selectedData[section] = selectedOptions;
      }
      setTimeout(() => {
        if (!lastClickedElement || lastClickedElement.closest("." + applyBtnClass).length || lastClickedElement.closest("." + clearBtnClass).length) {
          $(`.${selectClass}[data-id="${section}"]`).val(selectedOptions).trigger("change");
        }
      }, 100);
    });
  }

  function setSelectedOptions(dataId, values) {
    if (dataId === "") {
      $(`.${accordionFiltersClass} input`).prop("checked", false);
    } else {
      $(`.${accordionFiltersClass}[data-id="${dataId}"]`)
        .find("input")
        .each(function () {
          $(this).prop("checked", values.includes($(this).val()));
        });
    }
  }

  $("." + clearBtnClass).on("click", function () {
    updateSelectedOptions();
    setTimeout(() => {
      $("input[type=checkbox]").prop("checked", false);
      $("#filter-count").text(``);
      $("." + clearBtnClass).addClass("disabled");
      $("." + applyBtnClass).addClass("disabled");
      toggleFilter("close");
      updateSelectedOptions();
    }, 150);
  });

  $("." + applyBtnClass).on("click", function () {
    updateSelectedOptions();
    setTimeout(() => {
      if (SelectedFilters.length != 0) {
        $("#filter-count").text(`(${SelectedFilters.length})`);
      } else {
        $("#filter-count").text(``);
      }
      $(`.${mainContainerClass} .filters input[type='checkbox']`).each(
        function () {
          let checkbox = $(this);
          let isChecked = SelectedFilters.some(
            (filter) => filter.value === checkbox.val()
          );

          checkbox.prop("checked", isChecked);
        }
      );
      toggleFilter("close");
    }, 150);
  });

  $(document).on(
    "change",
    `.${accordionFiltersClass} input[type=checkbox]`,
    function () {
      const count = $(`.${accordionFiltersClass} input:checked`).length;
      const anyChecked = count > 0;
      if (SelectedFilters.length > 0) {
        $("." + applyBtnClass).toggleClass("disabled", false);
        $("." + clearBtnClass).toggleClass("disabled", false);
      } else {
        $("." + clearBtnClass).toggleClass("disabled", !anyChecked);
        $("." + applyBtnClass).toggleClass("disabled", !anyChecked);
      }
    }
  );
}


let allowOpen = true;

$("select").on('select2:opening', function (e) {
  if (!allowOpen) {
    allowOpen = true;
    return;
  }

  e.preventDefault();

  const selectElement = this;

  $('html, body').animate({
    scrollTop: $(selectElement).offset().top - $(".header").outerHeight() - 55
  }, 0, function () {
    allowOpen = false;

    setTimeout(() => {
      $(selectElement).select2('open');

      // Setup observer after dropdown is opened
      const observer = new MutationObserver(() => {
        const dropdown = document.querySelector('.select2-container--open .select2-dropdown');
        if (dropdown && dropdown.classList.contains('select2-dropdown--above')) {
          $(selectElement).select2('close');
          observer.disconnect();
        }
      });

      // Watch for changes in dropdown attributes or classes
      const dropdownNode = document.querySelector('.select2-container--open');
      if (dropdownNode) {
        observer.observe(dropdownNode, {
          attributes: true,
          subtree: true,
          attributeFilter: ['class']
        });
      }

      // Also clean up observer when dropdown is closed
      $(selectElement).on('select2:close.observerCleanup', function () {
        observer.disconnect();
        $(this).off('select2:close.observerCleanup');
      });

    }, 300);
  });
});

