function initTabScroll() {
  $(".sticky-slider.sm .accordion-button").click(function () {
    $("html,body").toggleClass("overflowHide");
  });

  $(".sticky-slider.sm .nav-link").click(function () {
    $("html,body").toggleClass("overflowHide");
  });

  function onScrollTabsActive() {
    const $navLinks = $(".sticky-slider ul .nav-link");
    const $sections = $("section[id]");
    let currentSectionid = "";

    $sections.each(function () {
      const sectionTop = $(this).offset().top - window.innerHeight * 0.5; // Start slightly earlier
      const sectionBottom =
        sectionTop + $(this).outerHeight() - window.innerHeight * 0.05; // End slightly later

      if (
        $(window).scrollTop() >= sectionTop &&
        $(window).scrollTop() < sectionBottom
      ) {
        currentSectionid = $(this).attr("id");
      }
    });

    if (currentSectionid) {
      $navLinks.each(function () {
        const $anchor = $(this).find("a");
        $(this).toggleClass(
          "active",
          $anchor.length && $anchor.attr("href") === `#${currentSectionid}`
        );
        if ($anchor.attr("href") === `#${currentSectionid}`) {
          $(".sticky-slider .mainTitle").text($anchor.text());
        }
      });
    }
  }

  function scrollTabs() {
    const $slider = $(".sticky-slider .tabs-wrapper ul");
    const $previousBtn = $(".sticky-slider .previous-btn");
    const $nextBtn = $(".sticky-slider .next-btn");
    const $sliderItems = $slider.find("li");
    let currentIndex = 0;
    const visibleItems = countVisibleItems();

    if ($sliderItems.length == countVisibleItems() + 1) {
      $nextBtn.addClass('disabled')
      $previousBtn.addClass('disabled')
    }

    function countVisibleItems() {
      if ($(".sticky-slider .tabs-wrapper ul")[0]) {
        const $container = $(".sticky-slider .tabs-wrapper ul")[0];
        const items = $container.children;
        const containerLeft = $container.scrollLeft;
        const containerRight = containerLeft + $container.clientWidth;

        let visibleCount = 0;

        for (let i = 0; i < items.length; i++) {
          const item = items[i];
          const itemLeft = item.offsetLeft;
          const itemRight = itemLeft + item.offsetWidth;

          if (itemRight > containerLeft && itemLeft < containerRight) {
            visibleCount++;
          }
        }

        return visibleCount - 1;
      }
    }

    function updateScroll() {
      let scrollPosition = 0;
      for (let i = 0; i < currentIndex; i++) {
        const $item = $sliderItems.eq(i);
        scrollPosition +=
          $item.outerWidth() + (parseFloat($slider.css("gap")) || 0);
      }
      $slider.animate({ scrollLeft: scrollPosition }, "smooth");

      $previousBtn.toggleClass("active", currentIndex > 0);

      if (currentIndex < $sliderItems.length - (visibleItems + 1)) {
        $nextBtn.addClass()
      }
      $nextBtn.toggleClass(
        "active",
        currentIndex < $sliderItems.length - (visibleItems + 1)
      );
    }

    $previousBtn.on("click", () => {
      if (currentIndex > 0) {
        currentIndex--;
        updateScroll();
      }
    });

    $nextBtn.on("click", () => {
      if (currentIndex < $sliderItems.length - visibleItems) {
        currentIndex++;
        updateScroll();
      }
    });

    $sliderItems.on("click", function () {

      currentIndex = $(this).index() - 1;

      if (currentIndex > $sliderItems.length - visibleItems) {
        currentIndex = $sliderItems.length - visibleItems;
      }

      updateScroll();
    });

    updateScroll();
  }


  function scrollToSection() {
    $(".sub-menu-sticky .sliderItem").on("click", function (event) {
      event.preventDefault();
      var target = $(this).attr("href");

      if (!target || !$(target).length) {
        return;
      }

      let extraSpace =
        window.innerWidth <= 600 ? -150 : window.innerHeight * 0.2;

      var targetOffset = $(target).offset();
      if (!targetOffset) {
        return;
      }

      var offset = $(".sub-menu-sticky").outerHeight() + extraSpace;

      setTimeout(() => {
        $("html, body").animate(
          {
            scrollTop: targetOffset.top - offset,
          },
          0
        );
      }, 500);
    });
  }

  $(window).on("scroll", onScrollTabsActive);
  scrollToSection();
  scrollTabs();
}

