const LazyLoadingImgLoader = new IntersectionObserver((entries, obs) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      const highImg = entry.target;
      const src = $(highImg).data("src");
      if (src) {
        highImg.src = src;
        highImg.onload = () => {
          $(highImg).css("opacity", 1);
        };
      }

      obs.unobserve(highImg);
    }
  });
}, {
  threshold: 0.1
});

function initGalleryViewer() {
  const $modal = $(".gallery-modal");
  const $prevBtn = $modal.find(".previous-btn");
  const $nextBtn = $modal.find(".next-btn");
  let currentIndex = -1;
  let $currentGallery = null;
  let $currentCardWraps = null;

  function updateNavigationButtons() {
    $prevBtn.toggleClass("active", currentIndex > 0);
    $nextBtn.toggleClass("active", currentIndex < $currentCardWraps.length - 1);
  }

  function galleryCardDetail($card) {
    const dataType = $card.attr("data-type");
    const dataVideoHost = $card.attr("data-video-host");
    const dataUrl = $card.attr("data-url");
    const dataLow = $card.attr("data-low-url");
    const title = $card.find(".title").text().trim() || " ";

    const paragraphs = $card.find("p").map(function () {
      return $(this).text().trim();
    }).get();

    const details = { title, paragraphs };

    if (dataType === "image") {
      details.img = dataUrl;
      details.lowImg = dataLow;
    } else if (dataType === "video") {
      details.video = { src: dataUrl, title };
    }

    updateNavigationButtons();

    const $modalHeader = $modal.find(".modal-header .title");
    const $modalBody = $modal.find(".modal-body");

    $modalHeader.fadeOut(100, function () {
      $(this).find("h5").text(details.title);
      $(this).find("p").html(details.paragraphs.join("<br>"));
      $(this).fadeIn(500);
    });

    $modalBody.fadeOut(100, function () {
      $(this).empty();

      if (details.video) {
        const videoEmbed = dataVideoHost === "youtube"
          ? `<iframe width="100%" height="100%" src="${details.video.src}" title="${details.video.title}" frameborder="0" allowfullscreen></iframe>`
          : `<video controls title="${details.video.title}"><source src="${details.video.src}" type="video/mp4">Your browser does not support the video tag.</video>`;
        $(this).append(videoEmbed);
      } else if (details.img) {
        const content = details.lowImg
          ? `<img src="${details.lowImg}" class="img-low" style="position:absolute;top:0;left:0;width:100%;z-index:1;">
             <img data-src="${details.img}" class="img-high" style="position:absolute;width:100%;opacity:0;z-index:2;transition:opacity 0.5s;" loading="lazy">`
          : `<img src="${details.img}" loading="lazy">`;
        $(this).append(content);

        if (details.lowImg) {
          setTimeout(() => {
            const highImg = $modalBody.find(".img-high")[0];
            if (highImg instanceof Element) {
              LazyLoadingImgLoader.observe(highImg);
            }
          }, 500);
        }
      }

      $(this).fadeIn(500);
    });
  }

  $(".galleryItems").each(function () {
    const $gallery = $(this);
    const $cardWraps = $gallery.find(".cardWrap");

    $cardWraps.on("mouseover", function () {
      currentIndex = $cardWraps.index(this);
      $currentCardWraps = $cardWraps;
      $currentGallery = $gallery;
      galleryCardDetail($(this));
    });

    $cardWraps.on("click", function () {
      currentIndex = $cardWraps.index(this);
      $currentCardWraps = $cardWraps;
      $currentGallery = $gallery;
      $("#gallery-viewer").fadeIn(600);
      $("html, body").addClass("overflowHide");
    });
  });

  function galleryCardDetailNext() {
    if ($currentCardWraps && currentIndex < $currentCardWraps.length - 1) {
      currentIndex++;
      galleryCardDetail($currentCardWraps.eq(currentIndex));
    }
  }

  function galleryCardDetailPrev() {
    if ($currentCardWraps && currentIndex > 0) {
      currentIndex--;
      galleryCardDetail($currentCardWraps.eq(currentIndex));
    }
  }

  $prevBtn.on("click", galleryCardDetailPrev);
  $nextBtn.on("click", galleryCardDetailNext);
}

function initModal() {
  $('a.open-modal').on('click', function (e) {
    e.preventDefault();
    $("html, body").addClass("overflowHide");

    const modalId = $(this).data('modal');
    const isSync = $(this).data('modal-sync');

    if (isSync === true) {
      const contentBody = $(this).closest('.content-body');

      contentBody.find('*').each(function () {
        let Content = this;
        const attributes = this.attributes;

        $.each(attributes, function (index, attribute) {
          if (attribute.name.startsWith('data-sync-id-')) {
            const modalElement = $('#' + modalId).find('[data-sync-id-' + attribute.name.substring(13) + ']');

            if (modalElement.length) {
              modalElement.html(Content.innerHTML);
            }
          }
        });
      });
    }

    $('#' + modalId).fadeIn();
  });

  $('.modal .close').on('click', function () {
    const $modal = $(this).closest('.modal');
    stopVideoInModal($modal);
    $modal.fadeOut();
    $("html, body").removeClass("overflowHide");
  });

  $('.modal').on('click', function (e) {
    const $modalContent = $(this).find('.modal-content');

    if (!$modalContent.is(e.target) && $modalContent.has(e.target).length === 0 && !$(e.target).closest('.control-btn').length) {
      const $modal = $(this);
      stopVideoInModal($modal);
      $modal.fadeOut();
      $("html, body").removeClass("overflowHide");
    }
  });

  function stopVideoInModal($modal) {
    $modal.find('video').each(function () {
      this.pause();
      this.currentTime = 0;
    });

    $modal.find('iframe').each(function () {
      const $iframe = $(this);
      const src = $iframe.attr('src');
      if (src && src.includes('youtube.com')) {
        $iframe.attr('src', '');
        setTimeout(() => {
          $iframe.attr('src', src);
        }, 100);
      }
    });
  }

}

