function adjustDropdownOverlapping() {
  $("select").each(function () {
    $(this).on('select2:open', function () {
      const $select = $(this);
      const header = $('.top-bar');
      const dropdownSelector = '.select2-container.select2-container--default.select2-container--open:has(.select2-dropdown--above)';

      function adjustDropdownPosition() {
        const $dropdown = $(dropdownSelector);
        if ($dropdown.length === 0 || $select.length === 0 || header.length === 0) return;

        const dropdownRect = $dropdown[0].getBoundingClientRect();
        const headerRect = header[0].getBoundingClientRect();

        setTimeout(() => {
          const isOverlappingHeader = dropdownRect.top < headerRect.bottom + 30;
          if (isOverlappingHeader) {
            const headerBottom = header.offset().top + header.outerHeight();
            const adjustedTop = headerBottom + 20;
            if ($dropdown.find('.select2-dropdown--above')) {
              $dropdown.css({
                top: `${adjustedTop}px`,
                position: 'absolute'
              });
            }
          }
        }, 200);
      }

      $(window).on('scroll.select2adjust', adjustDropdownPosition);
      $select.on('select2:close', function () {
        $(window).off('scroll.select2adjust');
      });
    });
  });
}

function observeAndAdjustHeight(containerSelector, internalTime = 1000) {
  const $container = $(containerSelector);

  $container.css('overflow', 'hidden');
  $container.height($container.outerHeight());

  const observer = new MutationObserver(() => {
    setTimeout(() => {
      const currentHeight = $container.height();

      $container.css('height', 'auto');
      const targetHeight = $container.outerHeight();

      $container.height(currentHeight);

      $container.stop().animate(
        { height: targetHeight },
        300
      );
    }, internalTime);
  });

  observer.observe($container[0], {
    childList: true,
    subtree: true,
  });

  // Return an object with a custom disconnect method
  return {
    observer,
    disconnect: () => {
      observer.disconnect();
      $container.stop(true, true).css('height', 'auto');
    }
  };
}


