function getAllowedValues(selector) {
  let allowedData = $(selector).data("allow");

  if (allowedData === undefined) {
    let hideData = $(selector).data("hide");

    if (typeof hideData === "string") {
      return {
        type: 'hide',
        values: hideData.split(',')
      };
    }

    return { type: 'hide', values: [] };
  } else {
    if (typeof allowedData === "string") {
      return {
        type: 'allow',
        values: allowedData.split(',')
      };
    }

    return { type: 'allow', values: [] };
  }
}

function hideDisallowedOptions(optionSelector, allowedObj, dataAttr) {
  if (allowedObj.values[0] != '') {
    $(optionSelector).each(function () {
      const value = $(this).data(dataAttr);

      if (allowedObj.type === 'allow') {
        // Remove if value NOT in allowed list
        if (!allowedObj.values.includes(value)) {
          $(this).remove();
        }
      } else if (allowedObj.type === 'hide') {
        // Remove if value IS in the hide list
        if (allowedObj.values.includes(value)) {
          $(this).remove();

        }
      }
    });
  }
}

function hideAllowCodeOptions() {
  // For NiceCountryInput
  if ($(".countrySelect > div").length !== 0) {
    const container = document.querySelector('.countrySelect > div');
    const priorityData = container.getAttribute('data-priority-countries');
    const priorityCountries = priorityData ? priorityData.split(',') : [];
    const listItems = document.querySelectorAll('.countrySelect .country-list-wrapper a');
    let order = 0;

    // Apply order to priority countries first
    priorityCountries.forEach(code => {
      const li = document.querySelector(`.countrySelect .country-list-wrapper a[data-countryiso="${code}"]`);
      if (li) {
        li.style.order = order++;
      }
    });

    // Remove old separator if any
    document.querySelectorAll('.countrySelect .country-list-wrapper .country-separator').forEach(el => el.remove());

    // Insert separator after preferred countries
    const lastPreferred = document.querySelector(`.countrySelect .country-list-wrapper a[data-countryiso="${priorityCountries[priorityCountries.length - 1]}"]`);
    if (lastPreferred) {
      const separator = document.createElement('div');
      separator.className = 'country-separator';
      separator.style.order = order++;
      lastPreferred.parentNode.appendChild(separator);
    }

    // Order remaining countries
    listItems.forEach(li => {
      const code = li.getAttribute('data-countryiso');
      if (!priorityCountries.includes(code)) {
        li.style.order = order++;
      }
    });
  }

  // For intl-tel-input
  if ($(".iti__selected-country").length !== 0) {
    $(".iti__selected-country").on("click", function () {
      const container = document.querySelector('.countrySelect > div');
      const priorityData = container ? container.getAttribute('data-priority-countries') : '';
      const priorityCountries = priorityData ? priorityData.split(',') : [];

      document.body.classList.add("intl-tel-open");
      document.documentElement.classList.add("intl-tel-open");

      // Close on outside click
      document.addEventListener("click", function handleOutsideClick(e) {
        const list = document.querySelector(".iti__country-list");
        const trigger = document.querySelector(".iti__selected-country");

        if (list && trigger && !trigger.contains(e.target) && !list.contains(e.target)) {
          document.body.classList.remove("intl-tel-open");
          document.documentElement.classList.remove("intl-tel-open");
          document.removeEventListener("click", handleOutsideClick);
        }
      });

      setTimeout(() => {
        const allLists = document.querySelectorAll('.iti__country-list'); // desktop + mobile
        allLists.forEach(list => {
          const listItems = list.querySelectorAll('li');
          let order = 0;

          // Clear all previous order & separators
          listItems.forEach(li => li.style.order = "");
          list.querySelectorAll('.country-separator').forEach(el => el.remove());

          // Preferred countries
          priorityCountries.forEach(code => {
            const li = list.querySelector(`li[data-country-code="${code}"]`);
            if (li) {
              li.style.order = order++;
            }
          });

          // Insert separator
          const lastPreferred = list.querySelector(`li[data-country-code="${priorityCountries[priorityCountries.length - 1]}"]`);
          if (lastPreferred) {
            const separator = document.createElement('li');
            separator.className = 'country-separator';
            separator.style.order = order++;
            list.appendChild(separator);
          }

          // Remaining countries
          listItems.forEach(li => {
            const code = li.getAttribute('data-country-code');
            if (!priorityCountries.includes(code)) {
              li.style.order = order++;
            }
          });
        });
      }, 10);
      setTimeout(() => {
        const handleOutsideClick = (e) => {
          const list = document.querySelector(".iti__country-list");
          const trigger = document.querySelector(".iti__selected-country");
      
          if (list && trigger && !trigger.contains(e.target) && !list.contains(e.target)) {
            document.body.classList.remove("intl-tel-open");
            document.documentElement.classList.remove("intl-tel-open");
            document.removeEventListener("click", handleOutsideClick);
          }
        };
        document.addEventListener("click", handleOutsideClick);
      }, 0);
    });
  }
}


