function handleAccordionHashOpen() {
  const hash = window.location.hash;
  if (!hash) return;

  const accordionItem = document.querySelector(hash);
  if (!accordionItem || !accordionItem.classList.contains('accordion-item')) return;

  // Step 1: Close all pre-opened accordions
  document.querySelectorAll('.accordion-collapse.show').forEach(collapse => {
    bootstrap.Collapse.getOrCreateInstance(collapse).hide();
  });

  // Step 2: Get parent tab and show it
  const tabPane = accordionItem.closest('.tab-pane');
  if (tabPane && !tabPane.classList.contains('active')) {
    const tabId = tabPane.id;

    const tabTrigger = document.querySelector(
      `[data-bs-toggle="tab"][href="#${tabId}"], [data-bs-toggle="tab"][data-bs-target="#${tabId}"]`
    );

    if (tabTrigger) {
      const tab = new bootstrap.Tab(tabTrigger);
      tab.show();

      // Wait for tab to fully show, then trigger accordion
      tabTrigger.addEventListener('shown.bs.tab', () => {
        setTimeout(() => {
          openAndScrollAccordion(accordionItem);
        }, 50); // Delay ensures tab pane is visible
      }, { once: true });

      return;
    }
  }

  // If already on the right tab
  openAndScrollAccordion(accordionItem);
}

function openAndScrollAccordion(item) {
  const collapse = item.querySelector('.accordion-collapse');

  if (!collapse) return;

  // Only open if not already shown
  if (!collapse.classList.contains('show')) {
    const instance = bootstrap.Collapse.getOrCreateInstance(collapse);
    instance.show();

    collapse.addEventListener('shown.bs.collapse', () => {
      const rect = item.getBoundingClientRect();
      const scrollTo = rect.top + window.scrollY - (window.innerHeight / 2) + (rect.height / 2);

      window.scrollTo({
        top: scrollTo,
        behavior: 'auto'
      });
    }, { once: true });
  } else {
    // If already open, scroll to it anyway
    const rect = item.getBoundingClientRect();
    const scrollTo = rect.top + window.scrollY - (window.innerHeight / 2) + (rect.height / 2);

    window.scrollTo({
      top: scrollTo,
      behavior: 'auto'
    });
  }
}

